code = """import json

# Load MongoDB documents
with open(var_functions.query_db:26, 'r') as f:
    civic_docs = json.load(f)

print('Loaded', len(civic_docs), 'civic documents')

# Extract project statuses from documents
project_statuses = {}
for doc in civic_docs:
    text = doc.get('text', '')
    lines = text.split('\n')
    current_section = None
    
    for i, line in enumerate(lines):
        line = line.strip()
        if not line:
            continue
        
        # Identify section headers
        if 'Design' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'design'
        elif 'Construction' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'construction'
        elif 'Not Started' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'not_started'
        
        # Extract project names from sections
        if current_section and len(line) > 10:
            # Skip markers and headers
            skip = ['(', '•', '■', 'Updates:', 'Schedule:', 'Project Description:', 'Page']
            if any(marker in line for marker in skip):
                continue
                
            # Look ahead for project indicators
            next_segment = '\n'.join(lines[i:i+4])
            if 'Updates:' in next_segment or 'Schedule:' in next_segment or 'Project Description:' in next_segment:
                base_name = line.split('(')[0].strip()
                
                if current_section == 'construction':
                    project_statuses[base_name] = 'completed'
                else:
                    project_statuses[base_name] = current_section

print('Found', len(project_statuses), 'project status mappings')
print('Status map preview:', dict(list(project_statuses.items())[:5]))

# Save status map for use in final answer
status_map = project_statuses
output = {
    'status_map_size': len(status_map),
    'status_map': status_map
}

print('__RESULT__:')
print(json.dumps(output))"""

